package com.example.ecommerce.order;

import java.util.UUID;
import javax.jws.WebService;

@WebService(endpointInterface = "com.example.ecommerce.order.OrderProcessingService",
            serviceName = "OrderProcessingWebService",
            portName = "OrderProcessingServicePort",
            targetNamespace = "http://order.ecommerce.example.com/")
public class OrderProcessingServiceImpl implements OrderProcessingService {

    @Override
    public OrderResponse processOrder(OrderRequest request) {
        OrderResponse response = new OrderResponse();
        double totalAmount = 0.0;

        // Validate request and process order items
        if (request != null && request.getOrderItems() != null) {
            for (OrderItem item : request.getOrderItems()) {
                // Basic validation for item data
                if (item.getPrice() > 0 && item.getQuantity() > 0) {
                    totalAmount += item.getPrice() * item.getQuantity();
                } else {
                    // Handle invalid item data, e.g., log, set error status, or throw SOAPFault
                    System.err.println("Invalid item data: productId=" + item.getProductId() +
                                       ", price=" + item.getPrice() + ", quantity=" + item.getQuantity());
                }
            }
        } else {
             // Handle empty or null request/items, e.g., set error status
             response.setOrderId("N/A");
             response.setTotalAmount(0.0);
             response.setStatusMessage("Error: Order request or items cannot be null.");
             System.err.println("Order request or items cannot be null for Customer ID: " + (request != null ? request.getCustomerId() : "N/A"));
             return response;
        }

        // Simulate order persistence or further processing
        String orderId = UUID.randomUUID().toString(); // Generate a unique order ID

        response.setOrderId(orderId);
        response.setTotalAmount(totalAmount);
        response.setStatusMessage("Order " + orderId + " processed successfully for Customer ID: " + request.getCustomerId());

        System.out.println("Processed Order ID: " + orderId +
                           ", Customer ID: " + request.getCustomerId() +
                           ", Total Amount: " + String.format("%.2f", totalAmount)); // Format for better logging

        return response;
    }
}

